#!/usr/bin/env python3
import json
import re
from pathlib import Path
from collections import defaultdict

bucket_path = Path("/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/characters-house-hightower-j-w")
prose_edges_dir = bucket_path / "prose-edges-haiku"
prose_edges_dir.mkdir(parents=True, exist_ok=True)

entities = ["leyton-hightower", "lymond-hightower", "lynesse-hightower", "lyonel-hightower", "malora-hightower"]

def classify_candidate(cand):
    """Carefully classify a single candidate based on evidence paragraph."""
    source = cand['source_slug']
    target = cand['target_slug']
    target_type = cand['target_type']
    evidence_para = cand.get('evidence_paragraph', '')
    valid_types = cand.get('valid_edge_types', [])
    section = cand.get('source_section', '')

    # Check for pre-rejection
    if '_python_prereject' in cand:
        prereject = cand['_python_prereject']
        if prereject == 'target-slug-unresolved':
            return {"decision": "escalate_disambiguation", "candidate_kind": "source_target", 
                    "source_slug": source, "target_candidates": [target], "evidence_snippet": evidence_para[:100],
                    "evidence_section": section, "anchor_text": cand.get('anchor_text', '')}
        elif prereject == 'evidence-paragraph-not-found':
            return {"decision": "reject_just_mention", "candidate_kind": "source_target",
                    "source_slug": source, "target_slug": target, "reason": "evidence-paragraph-not-found"}

    para_lower = evidence_para.lower()

    # =========== CHARACTER RELATIONSHIPS ===========

    if target_type == 'character.human':
        # PARENT_OF: explicit daughter/son/child
        if re.search(r'\bdaughter\b|\bson\b|\bchildren\b|\bchild\b', evidence_para):
            if 'PARENT_OF' in valid_types and 'youngest' in para_lower or 'eldest' in para_lower:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "PARENT_OF", "qualifier": "biological",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 1
                }

        # ALLIES_WITH: supports
        if re.search(r'\bsupports\b|\bsupported\b', evidence_para):
            if 'ALLIES_WITH' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "ALLIES_WITH",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 1
                }

        # DUELS: unhorsed, defeated
        if re.search(r'\bunhorsed\b|\bdefeated\b', evidence_para):
            if 'DUELS' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "DUELS",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 1
                }

        # MARRIES_OFF: marry, married, wed
        if re.search(r'\bmarry|married|wed\b', evidence_para):
            if 'MARRIES_OFF' in valid_types and target_type == 'character.human':
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "MARRIES_OFF",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # RESCUES: saved, rescued, retrieved
        if re.search(r'\brescued\b|\brescues\b|\bsaved\b', evidence_para):
            if 'RESCUES' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "RESCUES",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # COMMANDS: sends word, orders
        # But NOT if it's intermediary (Willas sends word TO Leyton about something)
        if re.search(r'\bsends word\b.*so.*leyton', evidence_para, re.IGNORECASE):
            # "Willas sends word so Leyton can..." - Willas is telling Leyton, not Leyton commanding
            pass
        elif re.search(r'\bcommands\b|\bsends.*to\b', evidence_para):
            if 'COMMANDS' in valid_types and source in para_lower:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "COMMANDS",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # ENCOUNTERS: met, meets
        staging_verbs = cand.get('staging_verbs_present', [])
        if staging_verbs and 'ENCOUNTERS' in valid_types:
            return {
                "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                "source_slug": source, "target_slug": target, "edge_type": "ENCOUNTERS",
                "evidence_snippet": evidence_para[:150], "evidence_section": section,
                "evidence_paragraph_index": 0, "confidence_tier": 1
            }

    # =========== LOCATION RELATIONSHIPS ===========

    elif target_type == 'place.location':
        # LOCATED_AT: at, atop, remains at, in
        if re.search(r'\batop\b|\bat\b|\bremains\b|\bdescended from\b', evidence_para):
            if 'LOCATED_AT' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "LOCATED_AT",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # Otherwise just mention for locations without direct relationship
        return {"decision": "reject_just_mention", "candidate_kind": "source_target",
                "source_slug": source, "target_slug": target, "reason": "no-fitting-type-vocab-locked"}

    # =========== EVENT RELATIONSHIPS ===========

    elif target_type.startswith('event'):
        # ATTENDS: present at, attended
        if re.search(r'\bpresent\b|\battended\b|\battend\b', evidence_para):
            if 'ATTENDS' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "ATTENDS",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # For event targets without explicit relationship verb - just mention
        return {"decision": "reject_just_mention", "candidate_kind": "source_target",
                "source_slug": source, "target_slug": target, "reason": "temporal-cooccurrence-not-relational"}

    # =========== MAGIC/CONCEPT RELATIONSHIPS ===========

    elif target_type == 'concept.magic':
        # PRACTICES: reading, studies, learns
        if re.search(r'\breading\b|\bstudies\b|\bpractices\b', evidence_para):
            if 'PRACTICES' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "PRACTICES",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

    # =========== ORGANIZATION/FACTION RELATIONSHIPS ===========

    elif target_type.startswith('organization'):
        # OPPOSES: threat, against, opposes
        if re.search(r'\bthreat\b|\bagainst\b|\boppose\b', evidence_para):
            if 'OPPOSES' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "OPPOSES",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

        # MEMBER_OF: member, part of
        if re.search(r'\bmember\b|\bpart of\b', evidence_para):
            if 'MEMBER_OF' in valid_types:
                return {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "MEMBER_OF",
                    "evidence_snippet": evidence_para[:150], "evidence_section": section,
                    "evidence_paragraph_index": 0, "confidence_tier": 2
                }

    # Default: reject as just mention
    return {"decision": "reject_just_mention", "candidate_kind": "source_target",
            "source_slug": source, "target_slug": target, "reason": "no-fitting-type-vocab-locked"}

# Process each entity
for entity_slug in entities:
    input_path = bucket_path / "prose-edge-candidates-enriched" / f"{entity_slug}.candidates.jsonl"
    output_path = prose_edges_dir / f"{entity_slug}.edges.jsonl"

    if not input_path.exists():
        print(f"[skip] {entity_slug}: input file not found")
        continue

    with open(input_path) as f:
        candidates = [json.loads(line) for line in f]

    edges = []
    for cand in candidates:
        decision = classify_candidate(cand)
        edges.append(decision)

    with open(output_path, 'w') as f:
        for edge in edges:
            f.write(json.dumps(edge) + '\n')

    # Count decisions
    counts = defaultdict(int)
    for e in edges:
        counts[e['decision']] += 1

    summary_parts = []
    for decision_type in ['emit_edge', 'reject_just_mention', 'escalate_cross_identity', 'escalate_disambiguation']:
        if counts[decision_type] > 0:
            summary_parts.append(f"{counts[decision_type]} {decision_type.split('_')[0]}")

    summary = ", ".join(summary_parts) if summary_parts else "0 decisions"
    print(f"[done] {entity_slug} → {summary} — wrote {output_path.name}")

